# scripts/check_train_scope.py
"""
Called by CI on release branches to validate that all commits are in scope.
Fails if any commit on the release branch is not in the approved scope document.
"""
import json, subprocess, sys
from pathlib import Path
from datetime import datetime, timezone

def get_commit_prs(base: str = "main") -> list[dict]:
    """List commits on this release branch not in main."""
    log = subprocess.check_output([
        "git", "log", f"{base}..HEAD",
        "--pretty=format:%H %s",
    ]).decode().strip()
    if not log:
        return []
    return [{"sha": line.split()[0], "msg": " ".join(line.split()[1:])}
            for line in log.splitlines()]

def get_train_scope(train_id: str) -> dict:
    scope_file = Path(f".github/trains/{train_id}.json")
    if not scope_file.exists():
        print(f"ERROR: No scope document found for train {train_id}")
        sys.exit(1)
    with open(scope_file) as f:
        return json.load(f)

def check_scope(train_id: str) -> None:
    scope = get_train_scope(train_id)
    freeze_time = datetime.fromisoformat(scope["freeze_time"])
    shipped = set(str(pr) for pr in scope["shipped_prs"])
    cherry_picks = set(str(cp) for cp in scope.get("cherry_picks", []))
    allowed = shipped | cherry_picks

    commits = get_commit_prs()
    violations = []

    for commit in commits:
        # Extract PR number from merge commit message: "Merge pull request #142 from..."
        pr_num = None
        for token in commit["msg"].split():
            if token.startswith("#") and token[1:].isdigit():
                pr_num = token[1:]
                break

        if pr_num and pr_num not in allowed:
            violations.append({
                "sha": commit["sha"][:8],
                "pr": pr_num,
                "msg": commit["msg"][:60],
            })

    if violations:
        print("SCOPE VIOLATION: commits on release branch not in approved scope:")
        for v in violations:
            print(f"  {v['sha']} PR#{v['pr']}: {v['msg']}")
        print(f"\nApproved PRs for train {train_id}: {sorted(allowed)}")
        sys.exit(1)

    print(f"Scope OK: {len(commits)} commits verified against train {train_id}")

if __name__ == "__main__":
    check_scope(sys.argv[1])
